import{c as e,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Memory for Autonomous LLM Agents: Mechanisms, Evaluation, and Emerging Frontiers","description":"","frontmatter":{"title":"Memory for Autonomous LLM Agents: Mechanisms, Evaluation, and Emerging Frontiers","arxiv_id":2603.0767,"published":"2026-03-08T00:00:00.000Z","source":"https://arxiv.org/abs/2603.07670","source_tier":"P"},"headers":[],"relativePath":"research/papers/2026-03-08-memory-autonomous-llm-agents-survey-2603-07670.md","filePath":"research/papers/2026-03-08-memory-autonomous-llm-agents-survey-2603-07670.md","lastUpdated":1779894392000}'),n={name:"research/papers/2026-03-08-memory-autonomous-llm-agents-survey-2603-07670.md"};function s(i,t,l,d,m,h){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="memory-for-autonomous-llm-agents-mechanisms-evaluation-and-emerging-frontiers" tabindex="-1">Memory for Autonomous LLM Agents: Mechanisms, Evaluation, and Emerging Frontiers <a class="header-anchor" href="#memory-for-autonomous-llm-agents-mechanisms-evaluation-and-emerging-frontiers" aria-label="Permalink to &quot;Memory for Autonomous LLM Agents: Mechanisms, Evaluation, and Emerging Frontiers&quot;">​</a></h1><p><strong>ArXiv</strong>: 2603.07670 | <strong>Date</strong>: 2026-03-08 | <strong>Author</strong>: Pengfei Du | <strong>Category</strong>: cs.AI</p><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>全面綜述 LLM 自主 agent 中記憶系統的設計、實作與評估方法，涵蓋 2022 至 2026 年初的研究。核心觀點：「單一 context window 遠不足以捕捉長期互動中發生的一切」，記憶是將無狀態文字生成器轉變為真正自適應系統的關鍵。</p><h2 id="核心貢獻" tabindex="-1">核心貢獻 <a class="header-anchor" href="#核心貢獻" aria-label="Permalink to &quot;核心貢獻&quot;">​</a></h2><h3 id="形式框架-write–manage–read-循環" tabindex="-1">形式框架：Write–Manage–Read 循環 <a class="header-anchor" href="#形式框架-write–manage–read-循環" aria-label="Permalink to &quot;形式框架：Write–Manage–Read 循環&quot;">​</a></h3><p>論文引入將 agent 記憶概念化為「write–manage–read 循環」的形式框架，整合感知與行動系統。</p><h3 id="三維分類法" tabindex="-1">三維分類法 <a class="header-anchor" href="#三維分類法" aria-label="Permalink to &quot;三維分類法&quot;">​</a></h3><p>記憶系統依三個維度分類：</p><ul><li><strong>時間範疇</strong>（Temporal scope）：短期 vs 長期</li><li><strong>表示基底</strong>（Representational substrate）：向量、圖、語言、代碼</li><li><strong>控制策略</strong>（Control policy）：靜態、動態、學習型</li></ul><h3 id="五大機制族群" tabindex="-1">五大機制族群 <a class="header-anchor" href="#五大機制族群" aria-label="Permalink to &quot;五大機制族群&quot;">​</a></h3><table tabindex="0"><thead><tr><th>機制</th><th>描述</th></tr></thead><tbody><tr><td>Context-resident compression</td><td>在有限 token 窗口內壓縮資訊</td></tr><tr><td>Retrieval-augmented stores</td><td>外部知識庫選擇性召回</td></tr><tr><td>Reflective self-improvement</td><td>從過去經驗中學習改進</td></tr><tr><td>Hierarchical virtual context</td><td>結構化階層組織資訊</td></tr><tr><td>Policy-learned management</td><td>AI 驅動的記憶保留/丟棄決策</td></tr></tbody></table><h2 id="主要發現" tabindex="-1">主要發現 <a class="header-anchor" href="#主要發現" aria-label="Permalink to &quot;主要發現&quot;">​</a></h2><ul><li><strong>評估轉向</strong>：從靜態回憶基準轉向多 session 測試（交織記憶與決策）</li><li><strong>4 個基準分析</strong>：揭示現有系統的持續差距</li><li><strong>5 個應用領域</strong>：個人助理、代碼 agent、開放世界遊戲、科學推理、多 agent 協作</li><li><strong>5 大開放挑戰</strong>：持續鞏固、因果接地檢索、可信反思、學習遺忘、多模態具身記憶</li></ul><h2 id="工程實踐考量" tabindex="-1">工程實踐考量 <a class="header-anchor" href="#工程實踐考量" aria-label="Permalink to &quot;工程實踐考量&quot;">​</a></h2><p>涵蓋：write-path filtering、衝突解決、延遲約束、隱私治理。</p><h2 id="與現有研究的關係" tabindex="-1">與現有研究的關係 <a class="header-anchor" href="#與現有研究的關係" aria-label="Permalink to &quot;與現有研究的關係&quot;">​</a></h2><table tabindex="0"><thead><tr><th>對比論文</th><th>差異</th></tr></thead><tbody><tr><td><code>2024-04-21-survey-memory-mechanism-llm-agents</code></td><td>本文聚焦機制族群分類，前者聚焦評估標準碎片化</td></tr><tr><td><code>2025-04-22-human-memory-to-ai-memory-survey</code></td><td>本文覆蓋更寬廣，前者從人類記憶視角切入</td></tr></tbody></table><h2 id="分類" tabindex="-1">分類 <a class="header-anchor" href="#分類" aria-label="Permalink to &quot;分類&quot;">​</a></h2><p><strong>Memory Architecture</strong> — 2026 年最全面的記憶機制綜述，write–manage–read 形式框架為設計新系統提供基礎。</p>',20)])])}const c=e(n,[["render",s]]);export{g as __pageData,c as default};
